schema.defaultValue:
#lt-root { position: absolute; bottom: 100px; left: 100px; display: flex; flex-direction: column; background: rgba(0,0,0,0.8); border-left: 6px solid var(--accent); padding: 20px 40px; border-radius: 4px; overflow: hidden; }
#lt-name { color: white; font-size: 60px; font-weight: bold; margin: 0; line-height: 1; }
#lt-role { color: #aaa; font-size: 30px; margin-top: 10px; line-height: 1; }

window.renderDVGE = (frame, props, ctx) => {
  const root = ctx.root.getElementById('lt-root');
  if (!root) return;
  const ip = ctx.timeline.introProgress;
  root.style.opacity = ip;
  root.style.transform = `translateX(${ctx.utils.lerp(-50, 0, ctx.utils.easeOutCubic(ip))}px)`;
};

#ticker-root { position: absolute; bottom: 50px; left: 50px; right: 50px; height: 60px; display: flex; background: rgba(0,0,0,0.8); border-radius: 8px; overflow: hidden; }
#ticker-label { background: var(--accent); color: white; padding: 0 30px; display: flex; align-items: center; font-size: 30px; font-weight: bold; z-index: 2; }
#ticker-track { flex: 1; position: relative; overflow: hidden; display: flex; align-items: center; }
#ticker-content { position: absolute; white-space: nowrap; color: white; font-size: 30px; left: 100%; }

window.renderDVGE = (frame, props, ctx) => {
  const content = ctx.root.getElementById('ticker-content');
  const root = ctx.root.getElementById('ticker-root');
  if (!content || !root) return;
  const ip = ctx.timeline.introProgress;
  root.style.opacity = ip;
  root.style.transform = `translateY(${ctx.utils.lerp(20, 0, ip)}px)`;
  const speed = 5;
  content.style.transform = `translateX(-${frame * speed}px)`;
};

/* @dv-prop { "id": "accentColor", "type": "color", "group": "Apariencia", "label": "Color de Acento", "defaultValue": "#ffffff" } */
/* @dv-prop { "id": "textColor", "type": "color", "group": "Apariencia", "label": "Color de Texto", "defaultValue": "#ffffff" } */
/* @dv-prop { "id": "fontSize", "type": "number", "group": "Apariencia", "label": "Tamaño Fuente", "defaultValue": 24 } */
/* @dv-prop { "id": "iconSize", "type": "number", "group": "Apariencia", "label": "Tamaño Icono", "defaultValue": 32 } */

#scene-wrapper {
    position: absolute;
    width: 100%;
    height: 100%;
    display: grid;
    place-items: var(--layoutPos);
    overflow: hidden;
    font-family: 'Inter', 'Segoe UI', sans-serif;
}

#social-grid {
    display: flex;
    flex-direction: column;
    gap: calc(var(--mainGap) * 1px);
    padding: 40px;
}

.social-item {
    display: flex;
    align-items: center;
    gap: 15px;
    position: relative;
    opacity: 0;
}

.icon-box {
    width: calc(var(--iconSize) * 1px);
    height: calc(var(--iconSize) * 1px);
    display: flex;
    align-items: center;
    justify-content: center;
}

.svg-icon {
    width: 100%;
    height: 100%;
    fill: var(--accentColor);
}

.handle {
    color: var(--textColor);
    font-size: calc(var(--fontSize) * 1px);
    font-weight: 600;
    letter-spacing: -0.02em;
    text-transform: uppercase;
}

.accent-line {
    position: absolute;
    bottom: -8px;
    left: 0;
    width: 0%;
    height: 2px;
    background: var(--accentColor);
}

// @dv-prop { "id": "globalOpacity", "type": "slider", "group": "Apariencia", "label": "Opacidad Global", "defaultValue": 100 } 
// @dv-prop { "id": "animCurve", "type": "easing", "group": "Animación", "label": "Curva de Entrada", "defaultValue": "[0.2, 1, 0.3, 1]" }
// @dv-prop { "id": "staggerDelay", "type": "number", "group": "Animación", "label": "Retraso (Offset)", "defaultValue": 0.15 }

window.renderDVGE = (frame, props, ctx) => {
    const intro = ctx.timeline.introProgress;
    const outro = ctx.timeline.outroProgress;
    const opacityMult = (props.globalOpacity ?? 100) / 100;

    const socialConfigs = [
        { id: 'fb', visible: props.showFB, text: props.userFB },
        { id: 'ig', visible: props.showIG, text: props.userIG },
        { id: 'x', visible: props.showX, text: props.userX },
        { id: 'tk', visible: props.showTK, text: props.userTK }
    ];

    const activeSocials = socialConfigs.filter(s => s.visible);

    socialConfigs.forEach((config, index) => {
        const el = ctx.root.getElementById(`item-${config.id}`);
        const textEl = ctx.root.getElementById(`text-${config.id}`);

        if (!el) return;

        if (!config.visible) {
            el.style.display = 'none';
            return;
        }

        el.style.display = 'flex';
        if (textEl) textEl.innerText = config.text;

        const activeIndex = activeSocials.indexOf(config);
        const startOffset = activeIndex * props.staggerDelay;
        const localIntro = ctx.utils.clamp((intro - startOffset) / (1 - startOffset || 1), 0, 1);

        const ease = ctx.utils.bezier(props.animCurve, localIntro);

        const opacity = ctx.utils.lerp(0, 1, ease) * ctx.utils.lerp(1, 0, outro) * opacityMult;
        const xPos = ctx.utils.lerp(-30, 0, ease);
        const lineScale = ctx.utils.lerp(0, 1, ease);

        el.style.opacity = opacity;
        el.style.transform = `translateX(${xPos}px)`;

        const line = el.querySelector('.accent-line');
        if (line) line.style.width = `${lineScale * 100}%`;
    });
};
